import{_ as e,o as t,c as r,ag as o}from"./chunks/framework.DXGyWiRo.js";const h=JSON.parse('{"title":"Cloud Platforms & Multi-Cloud","description":"","frontmatter":{},"headers":[],"relativePath":"en/infrastructure/cloud.md","filePath":"en/infrastructure/cloud.md"}'),i={name:"en/infrastructure/cloud.md"};function s(l,a,n,u,d,c){return t(),r("div",null,[...a[0]||(a[0]=[o(`<h1 id="cloud-platforms-multi-cloud" tabindex="-1">Cloud Platforms &amp; Multi-Cloud <a class="header-anchor" href="#cloud-platforms-multi-cloud" aria-label="Permalink to &quot;Cloud Platforms &amp; Multi-Cloud&quot;">​</a></h1><h2 id="cloud-computing-models" tabindex="-1">Cloud Computing Models <a class="header-anchor" href="#cloud-computing-models" aria-label="Permalink to &quot;Cloud Computing Models&quot;">​</a></h2><h3 id="iaas-infrastructure-as-a-service" tabindex="-1">IaaS (Infrastructure as a Service) <a class="header-anchor" href="#iaas-infrastructure-as-a-service" aria-label="Permalink to &quot;IaaS (Infrastructure as a Service)&quot;">​</a></h3><p>Raw compute, storage, and networking resources:</p><ul><li>Examples: EC2 (AWS), Compute Engine (GCP), VMs (Azure)</li><li>Use case: Full control, custom configurations</li></ul><h3 id="paas-platform-as-a-service" tabindex="-1">PaaS (Platform as a Service) <a class="header-anchor" href="#paas-platform-as-a-service" aria-label="Permalink to &quot;PaaS (Platform as a Service)&quot;">​</a></h3><p>Managed environments for running applications:</p><ul><li>Examples: Heroku, Cloud Run, App Engine</li><li>Use case: Focus on code, not infrastructure</li></ul><h3 id="saas-software-as-a-service" tabindex="-1">SaaS (Software as a Service) <a class="header-anchor" href="#saas-software-as-a-service" aria-label="Permalink to &quot;SaaS (Software as a Service)&quot;">​</a></h3><p>Fully managed applications:</p><ul><li>Examples: Salesforce, Gmail, GitHub</li><li>Use case: Use without hosting concerns</li></ul><h2 id="aws-amazon-web-services" tabindex="-1">AWS (Amazon Web Services) <a class="header-anchor" href="#aws-amazon-web-services" aria-label="Permalink to &quot;AWS (Amazon Web Services)&quot;">​</a></h2><p>Largest cloud provider with broadest service range.</p><h3 id="compute" tabindex="-1">Compute <a class="header-anchor" href="#compute" aria-label="Permalink to &quot;Compute&quot;">​</a></h3><ul><li><strong>EC2</strong>: Virtual machines with full control</li><li><strong>Lambda</strong>: Serverless functions</li><li><strong>ECS</strong>: Container orchestration (alternative to Kubernetes)</li><li><strong>EKS</strong>: Managed Kubernetes</li></ul><h3 id="storage" tabindex="-1">Storage <a class="header-anchor" href="#storage" aria-label="Permalink to &quot;Storage&quot;">​</a></h3><ul><li><strong>S3</strong>: Object storage (files, backups, static content)</li><li><strong>EBS</strong>: Block storage (databases, volumes)</li><li><strong>EFS</strong>: Network filesystem (shared storage)</li></ul><h3 id="database" tabindex="-1">Database <a class="header-anchor" href="#database" aria-label="Permalink to &quot;Database&quot;">​</a></h3><ul><li><strong>RDS</strong>: Managed relational databases (PostgreSQL, MySQL, MariaDB)</li><li><strong>DynamoDB</strong>: NoSQL key-value store</li><li><strong>ElastiCache</strong>: In-memory cache (Redis, Memcached)</li></ul><h3 id="networking" tabindex="-1">Networking <a class="header-anchor" href="#networking" aria-label="Permalink to &quot;Networking&quot;">​</a></h3><ul><li><strong>VPC</strong>: Virtual private cloud</li><li><strong>ELB/ALB</strong>: Load balancers</li><li><strong>Route 53</strong>: DNS service</li><li><strong>CloudFront</strong>: CDN</li></ul><h3 id="devops-services" tabindex="-1">DevOps Services <a class="header-anchor" href="#devops-services" aria-label="Permalink to &quot;DevOps Services&quot;">​</a></h3><ul><li><strong>CodePipeline</strong>: CI/CD orchestration</li><li><strong>CodeBuild</strong>: Build service</li><li><strong>CodeDeploy</strong>: Deployment automation</li><li><strong>CloudFormation</strong>: Infrastructure as Code</li></ul><h2 id="google-cloud-platform-gcp" tabindex="-1">Google Cloud Platform (GCP) <a class="header-anchor" href="#google-cloud-platform-gcp" aria-label="Permalink to &quot;Google Cloud Platform (GCP)&quot;">​</a></h2><p>Known for data processing and machine learning.</p><h3 id="compute-1" tabindex="-1">Compute <a class="header-anchor" href="#compute-1" aria-label="Permalink to &quot;Compute&quot;">​</a></h3><ul><li><strong>Compute Engine</strong>: Virtual machines</li><li><strong>App Engine</strong>: Managed application hosting</li><li><strong>Cloud Run</strong>: Serverless containers</li><li><strong>GKE</strong>: Managed Kubernetes</li></ul><h3 id="storage-1" tabindex="-1">Storage <a class="header-anchor" href="#storage-1" aria-label="Permalink to &quot;Storage&quot;">​</a></h3><ul><li><strong>Cloud Storage</strong>: Object storage</li><li><strong>Persistent Disk</strong>: Block storage</li><li><strong>Filestore</strong>: Network filesystem</li></ul><h3 id="database-1" tabindex="-1">Database <a class="header-anchor" href="#database-1" aria-label="Permalink to &quot;Database&quot;">​</a></h3><ul><li><strong>Cloud SQL</strong>: Managed databases</li><li><strong>Cloud Datastore</strong>: NoSQL database</li><li><strong>Bigtable</strong>: Large-scale NoSQL</li><li><strong>Firestore</strong>: Document database</li></ul><h3 id="unique-strengths" tabindex="-1">Unique Strengths <a class="header-anchor" href="#unique-strengths" aria-label="Permalink to &quot;Unique Strengths&quot;">​</a></h3><ul><li><strong>BigQuery</strong>: Data warehouse and analytics</li><li><strong>Cloud AI/ML</strong>: Machine learning services</li><li><strong>Dataflow</strong>: Stream and batch processing</li></ul><h2 id="microsoft-azure" tabindex="-1">Microsoft Azure <a class="header-anchor" href="#microsoft-azure" aria-label="Permalink to &quot;Microsoft Azure&quot;">​</a></h2><p>Strong enterprise integration and hybrid capabilities.</p><h3 id="compute-2" tabindex="-1">Compute <a class="header-anchor" href="#compute-2" aria-label="Permalink to &quot;Compute&quot;">​</a></h3><ul><li><strong>Virtual Machines</strong>: IaaS VMs</li><li><strong>App Service</strong>: Managed web applications</li><li><strong>Container Instances</strong>: Serverless containers</li><li><strong>AKS</strong>: Managed Kubernetes</li></ul><h3 id="storage-2" tabindex="-1">Storage <a class="header-anchor" href="#storage-2" aria-label="Permalink to &quot;Storage&quot;">​</a></h3><ul><li><strong>Blob Storage</strong>: Object storage</li><li><strong>Disk Storage</strong>: Block storage</li><li><strong>File Shares</strong>: Network filesystem</li></ul><h3 id="database-2" tabindex="-1">Database <a class="header-anchor" href="#database-2" aria-label="Permalink to &quot;Database&quot;">​</a></h3><ul><li><strong>Azure SQL</strong>: Managed SQL Server/PostgreSQL</li><li><strong>Cosmos DB</strong>: Globally distributed NoSQL</li><li><strong>Azure Database</strong>: Managed MySQL, PostgreSQL</li></ul><h3 id="unique-strengths-1" tabindex="-1">Unique Strengths <a class="header-anchor" href="#unique-strengths-1" aria-label="Permalink to &quot;Unique Strengths&quot;">​</a></h3><ul><li><strong>Active Directory Integration</strong>: Enterprise security</li><li><strong>Hybrid Cloud</strong>: Seamless on-premises integration</li><li><strong>Microsoft Stack Support</strong>: .NET, Office 365 integration</li></ul><h2 id="choosing-a-cloud-provider" tabindex="-1">Choosing a Cloud Provider <a class="header-anchor" href="#choosing-a-cloud-provider" aria-label="Permalink to &quot;Choosing a Cloud Provider&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Factor</th><th>AWS</th><th>GCP</th><th>Azure</th></tr></thead><tbody><tr><td>Market Share</td><td>Largest</td><td>Growing</td><td>Enterprise strong</td></tr><tr><td>Ease of Use</td><td>Steep</td><td>Moderate</td><td>Steep for enterprises</td></tr><tr><td>Cost</td><td>Competitive</td><td>Competitive</td><td>Competitive</td></tr><tr><td>Data/ML</td><td>Good</td><td>Excellent</td><td>Good</td></tr><tr><td>Enterprise</td><td>Mature</td><td>Growing</td><td>Excellent</td></tr><tr><td>Global Reach</td><td>Best</td><td>Best</td><td>Good</td></tr></tbody></table><h2 id="multi-cloud-strategy" tabindex="-1">Multi-Cloud Strategy <a class="header-anchor" href="#multi-cloud-strategy" aria-label="Permalink to &quot;Multi-Cloud Strategy&quot;">​</a></h2><h3 id="advantages" tabindex="-1">Advantages <a class="header-anchor" href="#advantages" aria-label="Permalink to &quot;Advantages&quot;">​</a></h3><ul><li>Avoid vendor lock-in</li><li>Leverage provider strengths</li><li>Disaster recovery across clouds</li><li>Compliance in different regions</li></ul><h3 id="challenges" tabindex="-1">Challenges <a class="header-anchor" href="#challenges" aria-label="Permalink to &quot;Challenges&quot;">​</a></h3><ul><li>Operational complexity</li><li>Team skill requirements</li><li>Cost management difficulty</li><li>Data egress costs</li></ul><h3 id="tools-for-multi-cloud" tabindex="-1">Tools for Multi-Cloud <a class="header-anchor" href="#tools-for-multi-cloud" aria-label="Permalink to &quot;Tools for Multi-Cloud&quot;">​</a></h3><p><strong>Kubernetes</strong></p><ul><li>Runs on any cloud provider</li><li>Portable workloads</li><li>Consistent API</li></ul><p><strong>Terraform</strong></p><ul><li>Cloud-agnostic IaC</li><li>Single configuration language</li></ul><p><strong>Multi-Cloud Platforms</strong></p><ul><li>HashiCorp Consul: Service mesh</li><li>CNCF Stackdriver: Observability</li></ul><h2 id="cost-optimization" tabindex="-1">Cost Optimization <a class="header-anchor" href="#cost-optimization" aria-label="Permalink to &quot;Cost Optimization&quot;">​</a></h2><h3 id="aws-cost-management" tabindex="-1">AWS Cost Management <a class="header-anchor" href="#aws-cost-management" aria-label="Permalink to &quot;AWS Cost Management&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Use AWS Cost Explorer</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Set up budget alerts</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Reserved instances for predictable workloads</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Spot instances for fault-tolerant workloads</span></span></code></pre></div><h3 id="cost-reduction-strategies" tabindex="-1">Cost Reduction Strategies <a class="header-anchor" href="#cost-reduction-strategies" aria-label="Permalink to &quot;Cost Reduction Strategies&quot;">​</a></h3><ol><li><strong>Right-sizing</strong>: Use appropriate instance types</li><li><strong>Auto-scaling</strong>: Scale down unused capacity</li><li><strong>Reserved Instances</strong>: Discounted long-term rates</li><li><strong>Spot Instances</strong>: Up to 90% cheaper, but interruptible</li><li><strong>Data Transfer</strong>: Minimize egress costs</li><li><strong>Storage Optimization</strong>: Archive old data</li></ol><h2 id="disaster-recovery" tabindex="-1">Disaster Recovery <a class="header-anchor" href="#disaster-recovery" aria-label="Permalink to &quot;Disaster Recovery&quot;">​</a></h2><h3 id="rto-rpo" tabindex="-1">RTO/RPO <a class="header-anchor" href="#rto-rpo" aria-label="Permalink to &quot;RTO/RPO&quot;">​</a></h3><ul><li><strong>RTO</strong> (Recovery Time Objective): Max acceptable downtime</li><li><strong>RPO</strong> (Recovery Point Objective): Max acceptable data loss</li></ul><h3 id="strategies" tabindex="-1">Strategies <a class="header-anchor" href="#strategies" aria-label="Permalink to &quot;Strategies&quot;">​</a></h3><p><strong>Backup &amp; Restore</strong></p><ul><li>RTO: Hours, RPO: Hours</li><li>Cheapest, slowest</li></ul><p><strong>Pilot Light</strong></p><ul><li>RTO: 10-15 minutes, RPO: Minutes</li><li>Minimal resources running</li></ul><p><strong>Warm Standby</strong></p><ul><li>RTO: Minutes, RPO: Seconds</li><li>Near full-capacity standby</li></ul><p><strong>Active-Active</strong></p><ul><li>RTO: None, RPO: None</li><li>Full replication, highest cost</li></ul><h2 id="hybrid-cloud" tabindex="-1">Hybrid Cloud <a class="header-anchor" href="#hybrid-cloud" aria-label="Permalink to &quot;Hybrid Cloud&quot;">​</a></h2><p>Combine on-premises and cloud infrastructure:</p><h3 id="aws-outposts" tabindex="-1">AWS Outposts <a class="header-anchor" href="#aws-outposts" aria-label="Permalink to &quot;AWS Outposts&quot;">​</a></h3><ul><li>AWS infrastructure on your premises</li><li>Consistent API and tooling</li><li>Low-latency connectivity</li></ul><h3 id="azure-stack" tabindex="-1">Azure Stack <a class="header-anchor" href="#azure-stack" aria-label="Permalink to &quot;Azure Stack&quot;">​</a></h3><ul><li>Azure services on-premises</li><li>Consistent experience</li><li>Flexible deployment options</li></ul><h2 id="security-in-cloud" tabindex="-1">Security in Cloud <a class="header-anchor" href="#security-in-cloud" aria-label="Permalink to &quot;Security in Cloud&quot;">​</a></h2><ol><li><strong>Identity &amp; Access</strong>: IAM policies, MFA</li><li><strong>Network</strong>: VPCs, firewalls, security groups</li><li><strong>Encryption</strong>: In-transit and at-rest</li><li><strong>Compliance</strong>: Meet regulatory requirements</li><li><strong>Monitoring</strong>: CloudTrail, VPC Flow Logs</li><li><strong>Secrets Management</strong>: AWS Secrets Manager, Azure Key Vault</li></ol><h2 id="cloud-native-architecture" tabindex="-1">Cloud-Native Architecture <a class="header-anchor" href="#cloud-native-architecture" aria-label="Permalink to &quot;Cloud-Native Architecture&quot;">​</a></h2><h3 id="characteristics" tabindex="-1">Characteristics <a class="header-anchor" href="#characteristics" aria-label="Permalink to &quot;Characteristics&quot;">​</a></h3><ul><li><strong>Microservices</strong>: Small, independent services</li><li><strong>Containers</strong>: Portable, lightweight deployments</li><li><strong>Serverless</strong>: Function-based computing</li><li><strong>Managed Services</strong>: Reduce operational burden</li><li><strong>Auto-scaling</strong>: Dynamic capacity adjustment</li><li><strong>Resilience</strong>: Handle failures gracefully</li></ul>`,85)])])}const p=e(i,[["render",s]]);export{h as __pageData,p as default};
